import{_ as a,c as e,a0 as i,o as t}from"./chunks/framework.BOr1CWtK.js";const r="/assets/holybroDrone/holybro_assembled.jpg",n="/assets/holybroDrone/pixhawk6c.jpg",u=JSON.parse('{"title":"Holybro X500 Drone","description":"","frontmatter":{},"headers":[],"relativePath":"docs/holybro/description.md","filePath":"docs/holybro/description.md"}'),s={name:"docs/holybro/description.md"};function l(d,o,c,p,h,m){return t(),e("div",null,o[0]||(o[0]=[i('<h1 id="holybro-x500-drone" tabindex="-1">Holybro X500 Drone <a class="header-anchor" href="#holybro-x500-drone" aria-label="Permalink to &quot;Holybro X500 Drone&quot;">​</a></h1><h2 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h2><p>The Holybro X500 is a robust, high-performance drone designed for research, education, and complex missions. It offers versatility and flexibility with its durable frame, supporting various payloads and equipment configurations for different applications.</p><h2 id="payload-capacity" tabindex="-1">Payload Capacity <a class="header-anchor" href="#payload-capacity" aria-label="Permalink to &quot;Payload Capacity&quot;">​</a></h2><ul><li><strong>Maximum Payload</strong>: Up to 2 kg</li></ul><h2 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h2><p><img src="'+r+'" alt="Holybro X500 Drone"></p><h3 id="components-used" tabindex="-1">Components Used <a class="header-anchor" href="#components-used" aria-label="Permalink to &quot;Components Used&quot;">​</a></h3><p><strong>Flight Controller</strong>:<br><a href="https://example.com/holybro-pixhawk-6x" target="_blank" rel="noreferrer">Holybro Pixhawk 6X</a></p><div style="display:flex;align-items:center;"><div style="flex:1;"><p> The Holybro Pixhawk 6X is a high-performance flight controller designed for demanding drone applications. Featuring a robust and versatile design, it integrates advanced flight control algorithms and a range of connectivity options into a single unit. This flight controller is ideal for both professional and hobbyist use, providing reliable and precise control for a variety of UAV platforms. </p></div><div style="flex:1;text-align:right;"><img src="'+n+'" alt="Holybro Pixhawk 6X" width="150" style="margin-right:0px;"></div></div><p><strong>Key Features:</strong></p><ul><li><strong>Advanced Processor:</strong> Equipped with a powerful ARM Cortex-M7 processor for efficient and responsive flight control.</li><li><strong>Multi-Sensor Suite:</strong> Integrates high-precision sensors including accelerometers, gyroscopes, and magnetometers for accurate stabilization.</li><li><strong>Connectivity Options:</strong> Supports multiple communication protocols such as UART, I2C, and CAN for versatile integration with various peripherals.</li><li><strong>Flight Software Compatibility:</strong> Compatible with popular flight control software like PX4 and ArduPilot for customizable and flexible operation.</li><li><strong>Built-in Redundancy:</strong> Includes features for system redundancy and fail-safes to enhance flight safety and reliability.</li><li><strong>Compact and Durable:</strong> Designed with a compact form factor and robust build quality, making it suitable for various drone applications and environments.</li></ul><h2 id="flight-time" tabindex="-1">Flight Time <a class="header-anchor" href="#flight-time" aria-label="Permalink to &quot;Flight Time&quot;">​</a></h2><ul><li><strong>Maximum Flight Time</strong>: 30-40 minutes (depending on payload and battery configuration)</li></ul><h2 id="application" tabindex="-1">Application <a class="header-anchor" href="#application" aria-label="Permalink to &quot;Application&quot;">​</a></h2><p>The Holybro X500 is ideal for applications such as research, educational training, professional mapping, advanced surveillance, and payload transportation tasks. Its modular and open-source design allows easy customization for specific project needs.</p><h2 id="components-used-1" tabindex="-1">Components Used <a class="header-anchor" href="#components-used-1" aria-label="Permalink to &quot;Components Used&quot;">​</a></h2><ul><li><strong>Flight Controller</strong>: Pixhawk 4</li><li><strong>Camera</strong>: Optional, supports multiple camera types (depending on use case)</li><li><strong>Motors</strong>: 2216 KV880 motors</li><li><strong>Batteries</strong>: 4S LiPo battery (supports up to 6S LiPo for extended flight time)</li></ul><h2 id="schematic" tabindex="-1">Schematic <a class="header-anchor" href="#schematic" aria-label="Permalink to &quot;Schematic&quot;">​</a></h2><p><img src="https://example.com/holybro_x500_schematic" alt="Holybro X500 Drone Schematic"></p>',20)]))}const f=a(s,[["render",l]]);export{u as __pageData,f as default};
